                    color: regularizationRate === rate ? (darkMode ? '#a5b4fc' : '#6366f1') : (darkMode ? '#e2e8f0' : '#374151')
                  }}
                >
                  {rate}
                </button>
              ))}
            </div>
          )}
        </div>
      </div>

      <div className="flex-grow"></div>

      {/* Dark Mode Toggle Button */}
      <button
